class Solution(object):
    def countOfSubstrings(self, word, k):
        vowels = set('aeiou')
        n = len(word)
        ans = 0
        for i in range(n):
            v_cnt = {}
            cons = 0
            for j in range(i, n):
                c = word[j]
                if c in vowels:
                    v_cnt[c] = v_cnt.get(c, 0) + 1
                else:
                    cons += 1
                if len(v_cnt) == 5 and cons == k:
                    ans += 1
        return ans
